#include <stdio.h>
#include <stdbool.h>
#include <string.h>

int graph[11][11];
int N;

bool dfs(int v, bool visited[], int cnt) {
    visited[v] = true;
    if (cnt == N) return true;
    for (int nxt = 1; nxt <= N; ++nxt) {
        if (graph[v][nxt] && !visited[nxt]) {
            if (dfs(nxt, visited, cnt + 1)) return true;
            visited[nxt] = false;
        }
    }
    return false;
}

bool hasHamiltonianPath() {
    bool visited[11];
    for (int start = 1; start <= N; ++start) {
        memset(visited, 0, sizeof(visited));
        if (dfs(start, visited, 1)) return true;
    }
    return false;
}

int main() {
    int T, M;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &N, &M);
        memset(graph, 0, sizeof(graph));
        for (int i = 0; i < M; ++i) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u][v] = graph[v][u] = 1;
        }
        printf("%d\n", hasHamiltonianPath() ? 1 : 0);
    }
    return 0;
}

