    static int N;
    static List<Integer>[] adj;

    static boolean dfs(int v, boolean[] used, int cnt) {
        used[v] = true;
        if (cnt == N) return true;
        for (int nxt : adj[v]) {
            if (!used[nxt]) {
                if (dfs(nxt, used, cnt + 1)) return true;
                used[nxt] = false;
            }
        }
        return false;
    }

