import sys
sys.setrecursionlimit(10000)

def has_hamiltonian_path(n, edges):
    graph = [[] for _ in range(n + 1)]
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def dfs(v, visited, cnt):
        visited[v] = True
        if cnt == n:
            return True
        for nxt in graph[v]:
            if not visited[nxt]:
                if dfs(nxt, visited, cnt + 1):
                    return True
                visited[nxt] = False
        return False

    for start in range(1, n + 1):
        visited = [False] * (n + 1)
        if dfs(start, visited, 1):
            return True
    return False

input_data = sys.stdin.read().strip().split()
if not input_data:
    sys.exit()
it = iter(input_data)
T = int(next(it))
out_lines = []
for _ in range(T):
    n = int(next(it))
    m = int(next(it))
    edges = [(int(next(it)), int(next(it))) for _ in range(m)]
    out_lines.append('1' if has_hamiltonian_path(n, edges) else '0')
print('\n'.join(out_lines))

