let idx = 0;
const T = Number(data[idx++]);
let results = [];
function hasHamiltonianPath(n, edges) {
  const adj = Array.from({ length: n + 1 }, () => []);
  for (const [u, v] of edges) {
    adj[u].push(v);
    adj[v].push(u);
  }
  function dfs(v, visited, cnt) {
    visited[v] = true;
    if (cnt === n) return true;
    for (const nxt of adj[v]) {
      if (!visited[nxt]) {
        if (dfs(nxt, visited, cnt + 1)) return true;
        visited[nxt] = false;
      }
    }
    return false;
  }
  const visited = new Array(n + 1).fill(false);
  for (let start = 1; start <= n; ++start) {
    visited.fill(false);
    if (dfs(start, visited, 1)) return true;
  }
  return false;
}
